 1→import { defineConfig } from 'vite';
 2→import react from '@vitejs/plugin-react';
 3→import path from 'path';
 4→
 5→export default defineConfig({
 6→  plugins: [react()],
 7→  build: {
 8→    rollupOptions: {
 9→      output: {
10→        manualChunks(id) {
11→          if (id.includes('node_modules/three')) {
12→            return 'three-vendor';
